-- CCN Council Prep Pro — OSCE practice questions batch
-- 42 questions tied to the new OSCE/Viva prep section, category='OSCE Practice'.
-- Includes several sourced directly from real JUTH exam papers (marked in the 'source' field)
-- and the Intensive Care Nursing OSCE Exam reference document; the rest are labeled
-- 'AI Practice Question' and grounded in the real procedure checklists supplied.
-- Run this once in the Supabase SQL Editor (Project -> SQL Editor -> New query).

on conflict (id) do update set topic=excluded.topic, source=excluded.source, q=excluded.q, opts=excluded.opts, ans_idx=excluded.ans_idx, exp=excluded.exp, category=excluded.category, category_icon=excluded.category_icon, is_active=true;